(147603, 'le-phenomene-du-coeur_206', NULL, 'event_le-phenomene-du-coeur_206_398606.jpg', NULL, NULL, 23508, 0, 0, '2016-10-14 11:28:49', '2016-10-14 11:28:51', 11817562, 'a:3:{s:10:"imageThumb";s:46:"evtbevent_le-phenomene-du-coeur_206_398606.jpg";s:9:"imageFull";s:45:"evfevent_le-phenomene-du-coeur_206_398606.jpg";s:5:"links";s:2:"[]";}', NULL, '{"citation":"VIVRE UN MOMENT D EXEPTION ET LA REALISATION SE SON R\\u00caVE SPORT","phenomenal":"Afin de promouvoir l\\u2019\\u00e9v\\u00e9nement, nous allons organiser dans les villes h\\u00f4tes (Nantes, Rouen, Paris, Montpellier, Metz, Lille, Grenoble ; Lyon) des go\\u00fbters-d\\u00e9dicaces dans les services p\\u00e9diatriques des h\\u00f4pitaux de ces villes avec des animations handball et accompagn\\u00e9s de handballeurs et handballeuses. La mise en place des go\\u00fbters est en cours d\\u2019\\u00e9laboration avec chaque \\u00e9tablissement, celui du centre hospitalier d''Arras, qui r\\u00e9unira une cinquantaine d''enfants et une dizaine de sportifs, est pr\\u00e9vu pour le 7 ou le 8 d\\u00e9cembre.","quisuisje":"Autre","partners":"Carrefour; P\\u00e9ricl\\u00e8s consulting","participants":"46"}', 7, 18, '["mi","pi"]', NULL),
(147602, 'le-handball-ne-forge-pas-le-caractere-des-ecoliers-d-aujourd-hui-mais-il-revele-celui-de-l-adulte-de-demain', NULL, NULL, NULL, NULL, 27716, 0, 0, '2016-10-14 11:25:48', '2016-10-14 11:25:48', 30399947, 'a:1:{s:5:"links";s:2:"[]";}', NULL, '{"citation":"- Faire du handball dans notre \\u00e9cole une activit\\u00e9 sportive phare. \\n- Toi et moi nous sommes diff\\u00e9rents, par notre \\u00e9ducation, notre aspect physique mais nous avons besoin l''un de l''autre et ce sport collectif nous permet de nous d\\u00e9couvrir. ","quisuisje":"usep","partners":"club de handibasket de la ville du Port et de La Possession et usep","participants":"146","phenomenal":"Activit\\u00e9s sur le temps de la pause m\\u00e9ridienne,\\nactivit\\u00e9s EPS avec le professeur sur le temps p\\u00e9dagogique\\nrencontre et mise en situation d''unit\\u00e9 d''apprentissage en situation de handensemble\\nrencontre et \\u00e9change sportif avec les parents \\nrencontre avec des champions de la discipline"}', 5, 11, NULL, NULL),
