(146846, 'pratique-d-activites-sportives-concues-comme-vecteur-de-citoyennete', NULL, 'event_pratique-d-activites-sportives-concues-comme-vecteur-de-citoyennete_215450.jpg', NULL, NULL, 27423, 0, 0, '2016-10-07 10:30:53', '2016-10-07 10:30:54', 54516597, 'a:3:{s:10:"imageThumb";s:88:"evtbevent_pratique-d-activites-sportives-concues-comme-vecteur-de-citoyennete_215450.jpg";s:9:"imageFull";s:87:"evfevent_pratique-d-activites-sportives-concues-comme-vecteur-de-citoyennete_215450.jpg";s:5:"links";s:2:"[]";}', NULL, '{"citation":"rencontre de J. Richardson lors du challenge \\u00e0 Dijon","phenomenal":"Rencontre avec un ancien international de hand ball, entra\\u00eeneur(J. Richardson) lors du challenge Michelet \\u00e0 Dijon en mai 2017.\\nValorisation du mondial lors des journ\\u00e9es de regroupements ritualis\\u00e9es, \\u00e9changes sur la citoyennet\\u00e9 \\u00e0 l''\\u00e9chelle mondiale, et les notions d''identit\\u00e9","quisuisje":"AssoCulturelle","partners":"PJJ, P\\u00f4le ressource SEMC, CREPS Paca, d\\u00e9l\\u00e9gation d\\u00e9partementales UFOLEP, d\\u00e9l\\u00e9gation r\\u00e9gionale L\\u00e9o Lagrange, Conseil r\\u00e9gional PACA, pr\\u00e9fecture des Bouches-du-Rh\\u00f4ne (FIPD), DRJSCS","participants":"200"}', 13, 17, '[]', NULL),
(146845, 'le-mondial-des-juniors', NULL, NULL, NULL, NULL, 27391, 1, 0, '2016-10-07 10:30:53', '2016-10-11 10:04:55', 92592114, 'a:1:{s:5:"links";s:2:"[]";}', NULL, '{"citation":"S''amuser, d\\u00e9couvrir, partager...\\nAller voir un match du mondial 2017 dans la salle de L\\u2019AccorHotels Arena.","quisuisje":"Collectivite","partners":"ALSH espace jeunesse, CSAKB","participants":"8","phenomenal":"1- Tournoi mixte, 8\\/11 ans\\n2- Avoir un minimum de 5 joueurs"}', 8, 11, NULL, NULL);
